import{_ as s,o as n,c as e,ak as i}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"Pod 网络通信：同一 Node 内与跨 Node 通信","description":"","frontmatter":{},"headers":[],"relativePath":"devops/k8s/pod-communication.md","filePath":"devops/k8s/pod-communication.md","lastUpdated":1774334277000}'),l={name:"devops/k8s/pod-communication.md"};function p(r,a,d,t,o,c){return n(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="pod-网络通信-同一-node-内与跨-node-通信" tabindex="-1">Pod 网络通信：同一 Node 内与跨 Node 通信 <a class="header-anchor" href="#pod-网络通信-同一-node-内与跨-node-通信" aria-label="Permalink to “Pod 网络通信：同一 Node 内与跨 Node 通信”">​</a></h1><p>「两个 Pod 之间是怎么通信的？」——表面上这是一个简单问题，但背后涉及网络命名空间、veth-pair、网桥、路由表、封包解包等多个层面的知识。</p><p>这一篇，我们从数据包在 K8s 集群中的完整旅程出发，拆解 Pod 网络通信的每一个环节。</p><h2 id="同一-node-内-pod-通信" tabindex="-1">同一 Node 内 Pod 通信 <a class="header-anchor" href="#同一-node-内-pod-通信" aria-label="Permalink to “同一 Node 内 Pod 通信”">​</a></h2><h3 id="关键概念-veth-pair" tabindex="-1">关键概念：veth-pair <a class="header-anchor" href="#关键概念-veth-pair" aria-label="Permalink to “关键概念：veth-pair”">​</a></h3><p>每个 Pod 都有自己独立的网络命名空间（network namespace）。Pod 和宿主机之间通过 <strong>veth-pair</strong>（Virtual Ethernet Pair）连接——就像一根虚拟网线，一端在 Pod 里，一端在宿主机上。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌──────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  Node 1                      │</span></span>
<span class="line"><span>│                                              │</span></span>
<span class="line"><span>│  ┌─────────────────┐     ┌──────────────┐  │</span></span>
<span class="line"><span>│  │   Pod A          │     │  Pod B        │  │</span></span>
<span class="line"><span>│  │  eth0            │     │  eth0         │  │</span></span>
<span class="line"><span>│  │  10.244.1.15     │     │  10.244.1.16  │  │</span></span>
<span class="line"><span>│  └───────┬─────────┘     └──────┬───────┘  │</span></span>
<span class="line"><span>│          │ veth-pair-A           │ veth-pair-B</span></span>
<span class="line"><span>│          │                       │          │</span></span>
<span class="line"><span>│          ▼                       ▼          │</span></span>
<span class="line"><span>│      docker0 / cni0 (bridge)               │</span></span>
<span class="line"><span>│      10.244.1.1                               │</span></span>
<span class="line"><span>│          │                                    │</span></span>
<span class="line"><span>│          │  ARP: who has 10.244.1.16?        │</span></span>
<span class="line"><span>│          ◄───────────────────────────────────►</span></span>
<span class="line"><span>│                                              │</span></span>
<span class="line"><span>└──────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><h3 id="通信流程" tabindex="-1">通信流程 <a class="header-anchor" href="#通信流程" aria-label="Permalink to “通信流程”">​</a></h3><ol><li>Pod A 想发包给 Pod B（目标 IP：10.244.1.16）</li><li>Pod A 查看本地路由，发现目标在同一网段，通过 eth0 发出</li><li>数据包通过 veth-pair 到达宿主机 bridge（cni0）</li><li>Bridge 上有 ARP 表，知道 10.244.1.16 对应 veth-pair-B</li><li>数据包通过 veth-pair-B 到达 Pod B</li></ol><p>整个过程在二层（数据链路层）完成，通过 ARP 解析 MAC 地址，Bridge 负责转发，无需出节点。</p><h2 id="跨-node-pod-通信" tabindex="-1">跨 Node Pod 通信 <a class="header-anchor" href="#跨-node-pod-通信" aria-label="Permalink to “跨 Node Pod 通信”">​</a></h2><h3 id="场景描述" tabindex="-1">场景描述 <a class="header-anchor" href="#场景描述" aria-label="Permalink to “场景描述”">​</a></h3><p>Pod A 在 Node 1（10.244.1.15），Pod B 在 Node 2（10.244.2.20）。跨节点通信是更复杂的情况，实现方式取决于 CNI 插件。</p><h3 id="方式一-flannel-vxlan-overlay" tabindex="-1">方式一：Flannel（VXLAN Overlay） <a class="header-anchor" href="#方式一-flannel-vxlan-overlay" aria-label="Permalink to “方式一：Flannel（VXLAN Overlay）”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Node 1 (IP: 192.168.1.10)              Node 2 (IP: 192.168.1.20)</span></span>
<span class="line"><span>┌───────────────────────┐            ┌───────────────────────┐</span></span>
<span class="line"><span>│ Pod A: 10.244.1.15   │            │ Pod B: 10.244.2.20   │</span></span>
<span class="line"><span>│         │            │            │         │            │</span></span>
<span class="line"><span>│         ▼            │            │         ▼            │</span></span>
<span class="line"><span>│     veth-A           │            │     veth-B           │</span></span>
<span class="line"><span>│         │            │            │         │            │</span></span>
<span class="line"><span>│    cni0 bridge        │◄── VXLAN ──►   cni0 bridge        │</span></span>
<span class="line"><span>│         │            │   tunnel   │         │            │</span></span>
<span class="line"><span>└─────────┼────────────┘            └─────────┼────────────┘</span></span>
<span class="line"><span>          │                                  │</span></span>
<span class="line"><span>          └──────────► 物理网络 ◄───────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong>封装过程（Node 1 发送）</strong>：</p><ol><li>Pod A 发送原始数据包：<code>Src=10.244.1.15, Dst=10.244.2.20</code></li><li>cni0 发现目标不在本地子网，交给 Flannel 处理</li><li>Flannel 查询 etcd，找到目标 Pod 所在节点的公网 IP（192.168.1.20）</li><li>在原包外再封一层头：<code>Outer Src=192.168.1.10, Outer Dst=192.168.1.20</code></li><li>通过物理网络发送到 Node 2</li></ol><p><strong>解封装过程（Node 2 接收）</strong>：</p><ol><li>Node 2 收到 VXLAN 封包，kernel 识别为 VXLAN 流量</li><li>去掉外层头，还原原始数据包</li><li>根据目标 IP（10.244.2.20）通过 ARP 找到对应 veth-pair</li><li>数据包通过 veth-pair 到达 Pod B</li></ol><h3 id="方式二-calico-路由模式" tabindex="-1">方式二：Calico（路由模式） <a class="header-anchor" href="#方式二-calico-路由模式" aria-label="Permalink to “方式二：Calico（路由模式）”">​</a></h3><p>Calico 不用封包，直接在物理网络上路由。关键依赖是 <strong>BGP（Border Gateway Protocol）</strong>：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Node 1 上的路由表示例</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 目的网络              网关              接口</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">10.244.2.0/24</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      via</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.1.20</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    eth0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ol><li>Pod A 发包：<code>Src=10.244.1.15, Dst=10.244.2.20</code></li><li>cni0 发现目标不在本地子网，查路由表</li><li>路由表显示下一跳是 <code>192.168.1.20</code>（Node 2 的物理 IP）</li><li>直接发包到物理网络（无封装），路由到 Node 2</li><li>Node 2 根据路由表将包送到对应 Pod</li></ol><p>Calico 的 BGP 路由反射器（Route Reflector）负责在节点之间传播路由信息，避免每对节点之间都建立 BGP 对等关系。</p><h3 id="方式三-cilium-ebpf" tabindex="-1">方式三：Cilium（eBPF） <a class="header-anchor" href="#方式三-cilium-ebpf" aria-label="Permalink to “方式三：Cilium（eBPF）”">​</a></h3><p>CILIUM 跳过了 cni0 bridge，直接在 eBPF 层处理：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Pod A eth0</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>eBPF Hook (Cilium Endpoint)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──► 本地 Pod（同节点）：直接通过 veth 转发</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └──► 远程 Pod（跨节点）：查 LXC 映射表，找对端 Node IP，通过 eth0 直接发送</span></span>
<span class="line"><span>                                      （VXLAN 在 eBPF 层封装，比内核更快）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>Cilium 的关键优化：</p><ul><li>绕过 cni0 bridge，避免 bridge 的 ARP 广播开销</li><li>通过 LXC 映射表直接找到对端节点 IP</li><li>eBPF 在内核执行，效率远高于 iptables 规则匹配</li></ul><h2 id="service-通信的特殊性" tabindex="-1">Service 通信的特殊性 <a class="header-anchor" href="#service-通信的特殊性" aria-label="Permalink to “Service 通信的特殊性”">​</a></h2><p>Pod 直接通信用 Pod IP，但 Pod IP 是不稳定的——每次 Pod 重启、调度、扩缩容都可能改变。Service 提供了稳定的接入点，但它的通信路径更复杂：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Pod A → ClusterIP → kube-proxy（iptables/IPVS）→ DNAT → 后端 Pod B</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个过程中，kube-proxy 将「访问 Service IP」的数据包修改为「访问后端 Pod IP」，然后正常走 Pod 网络的路由路径。</p><h2 id="关键知识点总结" tabindex="-1">关键知识点总结 <a class="header-anchor" href="#关键知识点总结" aria-label="Permalink to “关键知识点总结”">​</a></h2><table tabindex="0"><thead><tr><th>通信类型</th><th>路径</th><th>关键技术</th></tr></thead><tbody><tr><td>同节点 Pod 通信</td><td>Pod A → veth → Bridge → veth → Pod B</td><td>二层转发，ARP</td></tr><tr><td>跨节点通信（Flannel）</td><td>原始包 + VXLAN 封装 → 物理网络 → 解封装 → Pod</td><td>Overlay 封装</td></tr><tr><td>跨节点通信（Calico）</td><td>Pod IP 直接在物理网上路由</td><td>BGP 路由分发</td></tr><tr><td>跨节点通信（Cilium）</td><td>eBPF 直接处理，减少内核路径</td><td>eBPF + LXC 映射</td></tr><tr><td>Service 通信</td><td>Pod → ClusterIP → DNAT → Pod</td><td>iptables/IPVS</td></tr></tbody></table><h2 id="常见面试问题" tabindex="-1">常见面试问题 <a class="header-anchor" href="#常见面试问题" aria-label="Permalink to “常见面试问题”">​</a></h2><h3 id="为什么-pod-和-pod-之间可以直接通过-ip-通信-不需要-nat" tabindex="-1">为什么 Pod 和 Pod 之间可以直接通过 IP 通信，不需要 NAT？ <a class="header-anchor" href="#为什么-pod-和-pod-之间可以直接通过-ip-通信-不需要-nat" aria-label="Permalink to “为什么 Pod 和 Pod 之间可以直接通过 IP 通信，不需要 NAT？”">​</a></h3><p>这是 K8s 网络模型的三条核心约束之一。不同于传统 Docker 的 NAT 模式，K8s 要求 Pod IP 在整个集群内可路由。这是为了简化网络模型，让服务发现和负载均衡更容易实现。</p><h3 id="veth-pair-为什么叫「pair」" tabindex="-1">veth-pair 为什么叫「pair」？ <a class="header-anchor" href="#veth-pair-为什么叫「pair」" aria-label="Permalink to “veth-pair 为什么叫「pair」？”">​</a></h3><p>因为它是一对虚拟网卡，一端在 Pod 命名空间，一端在宿主机命名空间。数据从一端进，必然从另一端出。这种设计天然打通了容器和宿主机之间的网络通道。</p><h3 id="跨节点通信中-「抓包」能看到原始-pod-ip-还是封包后的-ip" tabindex="-1">跨节点通信中，「抓包」能看到原始 Pod IP 还是封包后的 IP？ <a class="header-anchor" href="#跨节点通信中-「抓包」能看到原始-pod-ip-还是封包后的-ip" aria-label="Permalink to “跨节点通信中，「抓包」能看到原始 Pod IP 还是封包后的 IP？”">​</a></h3><p>取决于抓包的位置：</p><ul><li>在 Pod 内抓包：只能看到原始包（Pod IP）</li><li>在 Node 上用 tcpdump 抓物理网卡：Flannel 模式下看到的是 VXLAN 封包（Outer IP），Calico 模式下看到的是原始 Pod IP</li></ul><h2 id="面试追问方向" tabindex="-1">面试追问方向 <a class="header-anchor" href="#面试追问方向" aria-label="Permalink to “面试追问方向”">​</a></h2><ul><li>Flannel VXLAN 的封包/解包在哪个层面发生？对性能有什么影响？</li><li>Calico 的 BGP Route Reflector 是怎么工作的？为什么需要它？</li><li>Cilium 为什么比传统 CNI 快？eBPF 在其中扮演了什么角色？</li><li>Pod 网络命名空间和宿主机之间还有哪些隔离点（UTS、PID、Mount）？</li></ul><blockquote><p>Pod 网络通信的底层原理，是理解整个 K8s 网络体系的基础。无论是故障排查还是性能优化，都需要深入到这一层才能找到根本答案。</p></blockquote>`,46)])])}const P=s(l,[["render",p]]);export{b as __pageData,P as default};
